import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.util.HashMap;
import java.util.Map;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;

public class XMLConfigParser {

    public static Map<String, String> parseConfig(byte[] xmlConfig) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setEntityResolver(new EntityResolverImpl()); // Resolve entity references
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.parse(new ByteArrayInputStream(xmlConfig));

        Map<String, String> config = new HashMap<>();
        parseNode(doc.getDocumentElement(), config);

        return config;
    }

    private static void parseNode(Node node, Map<String, String> config) {
        if (node.getNodeType() == Node.ELEMENT_NODE) {
            Element element = (Element) node;
            config.put(element.getTagName(), element.getTextContent());

            for (Node child = node.getFirstChild(); child != null; child = child.getNextSibling()) {
                parseNode(child, config);
            }
        }
    }
}